use strict;
use warnings;
use CGI qw(:standard);
use Storable qw(nstore retrieve);

# Function to create or update a session
sub save_session {
    my ($session_id, $data) = @_;
    nstore($data, "/tmp/sess_$session_id");
}

# Function to load a session
sub load_session {
    my ($session_id) = @_;
    return retrieve("/tmp/sess_$session_id");
}

# Main script logic
my $cgi = CGI->new;
