} else {
    # Load the existing session
    my $session_data = load_session($session_id);
    if (!$session_data) {
        # If session data is not found, create a new empty session
        save_session($session_id, {});
        $session_data = {};
    }
    # Update session data as needed (example: increment a counter)
    $session_data->{counter}++;
    save_session($session_id, $session_data);
}

